framework_css:
/*
  Global Design System
  Derived from provided design: modern, minimal, industrial/tech feel
*/

:root {
  /* Color palette */
  --color-primary-brown: #403726;    /* Header top band */
  --color-primary-green-dark: #33594B; /* Nav bar & dark accents */
  --color-primary-green: #4FA190;    /* Page background teal */
  --color-accent: #4FA190;

  --color-neutral-white: #FFFFFF;
  --color-neutral-offwhite: #F7F7F7;
  --color-neutral-black: #222222;

  --color-success: #3A7D5A;
  --color-error: #C6473F;
  --color-warning: #D29B3A;
  --color-info: #2F6F82;

  /* Typography */
  --font-heading: 'Oswald', Helvetica, sans-serif;
  --font-body: 'Work Sans', Arial, sans-serif;
  --font-code: 'Fira Code', monospace;

  --font-size-h1: 48px;
  --font-size-h2: 32px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (base 8px) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;

  /* Layout */
  --container-max-width: 1100px;
}

/* Global reset-ish styles */

* {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-black);
  background-color: var(--color-primary-green);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 2px;
}

p {
  margin-top: 0;
  margin-bottom: var(--space-sm);
}

ul,
ol {
  margin-top: 0;
  padding-left: 1.25rem;
}

/* Layout helpers */

.container {
  max-width: var(--container-max-width);
  margin: 0 auto;
  padding-left: 24px;
  padding-right: 24px;
}

/* Header */

.site-header {
  color: var(--color-neutral-white);
  font-family: var(--font-heading);
}

.header-top {
  background-color: var(--color-primary-brown);
  padding-top: var(--space-lg);
  padding-bottom: var(--space-lg);
}

.header-top-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.branding-link {
  color: inherit;
  text-decoration: none;
}

.site-title {
  margin: 0 0 var(--space-xs) 0;
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-bold);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  line-height: var(--line-height-tight);
}

.site-tagline {
  margin: 0;
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.header-meta {
  min-width: 48px; /* keeps layout similar to design even when empty */
}

/* Primary navigation bar */

.primary-nav {
  background-color: var(--color-primary-green-dark);
}

.nav-list {
  display: flex;
  align-items: center;
  gap: var(--space-md);
  list-style: none;
  margin: 0;
  padding: 0;
}

.nav-item {
  margin: 0;
}

.nav-link {
  display: inline-block;
  padding-top: var(--space-sm);
  padding-bottom: var(--space-sm);
  font-family: var(--font-heading);
  font-size: 15px;
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-neutral-white);
}

.nav-link:hover,
.nav-link:focus-visible {
  color: var(--color-neutral-white);
  border-bottom: 2px solid var(--color-accent);
}

.nav-link.is-active {
  font-weight: var(--font-weight-semibold);
}

/* Page background & main content card */

.page-background {
  background-color: var(--color-primary-green);
  padding-top: var(--space-lg);
  padding-bottom: var(--space-xl);
}

.site-main {
  margin-bottom: var(--space-xl);
}

.content-card {
  background-color: var(--color-neutral-white);
  padding: var(--space-xl) var(--space-xl);
  margin-top: var(--space-md);
  margin-bottom: var(--space-lg);
  border-radius: 0;
  box-shadow: none;
}

/* Optional card header styles (for page-specific use) */

.content-card-header {
  margin-bottom: var(--space-lg);
  border-bottom: 2px solid var(--color-primary-green-dark);
  padding-bottom: var(--space-sm);
}

.content-card-title {
  margin: 0 0 var(--space-sm) 0;
  font-family: var(--font-heading);
  font-size: var(--font-size-h2);
  font-weight: var(--font-weight-semibold);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--color-primary-green-dark);
}

/* Footer */

.site-footer {
  background-color: var(--color-primary-green-dark);
  color: var(--color-neutral-white);
  font-family: var(--font-body);
  padding-top: var(--space-lg);
  padding-bottom: var(--space-lg);
}

.footer-inner {
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
}

.footer-nav-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-md);
}

.footer-link {
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  text-transform: uppercase;
  letter-spacing: 0.16em;
  color: var(--color-neutral-white);
}

.footer-link:hover,
.footer-link:focus-visible {
  text-decoration: underline;
}

.footer-meta {
  margin: 0;
  font-size: var(--font-size-small);
  opacity: 0.9;
}

/* Code blocks (for future blog/tech content) */

code,
pre {
  font-family: var(--font-code);
}

pre {
  background-color: var(--color-neutral-offwhite);
  padding: var(--space-sm);
  overflow-x: auto;
}

/* Responsive adjustments */

@media (max-width: 768px) {
  .header-top-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-sm);
  }

  .nav-list {
    flex-wrap: wrap;
    gap: var(--space-sm);
  }

  .nav-link {
    padding-top: var(--space-xs);
    padding-bottom: var(--space-xs);
  }

  .content-card {
    padding: var(--space-lg) var(--space-md);
  }
}

@media (max-width: 480px) {
  .site-title {
    font-size: 36px;
  }

  .site-tagline {
    font-size: 13px;
  }
}
